/**
 * Unit tests for elicitation/elicitation-result-logger (#1264 Phase 3).
 *
 * Fires on the CC `ElicitationResult` event (after the user responds). Reads CC's
 * documented payload ({ server_name, user_response: { action, content } }). The
 * prior code read invented fields (elicitation_action / mcp_server_name) and tried
 * to inject additionalContext on decline — but CC strips additionalContext on
 * ElicitationResult (#1794), so that branch was dead. It is now log-only.
 */

import { describe, it, expect, vi } from 'vitest';
import type { HookInput } from '../../types.js';

vi.mock('../../lib/common.js', async () => {
  const actual = await vi.importActual<typeof import('../../lib/common.js')>('../../lib/common.js');
  return {
    ...actual,
    outputSilentSuccess: vi.fn(() => ({ continue: true, suppressOutput: true })),
  };
});

import { elicitationResultLogger } from '../../elicitation/elicitation-result-logger.js';

function result(overrides: Partial<HookInput> = {}): HookInput {
  return {
    hook_event: 'ElicitationResult',
    hook_event_name: 'ElicitationResult',
    tool_name: 'collect_input',
    session_id: 'test',
    tool_input: {},
    project_dir: '/test',
    server_name: 'some-mcp',
    user_response: { action: 'accept', content: {} },
    ...overrides,
  } as HookInput;
}

describe('elicitation/elicitation-result-logger (#1264 Phase 3 — real CC payload)', () => {
  it('is log-only — silent success, no dead additionalContext injection', () => {
    const r = elicitationResultLogger(result({ user_response: { action: 'decline' } }));
    expect(r.continue).toBe(true);
    expect(r.suppressOutput).toBe(true);
    // additionalContext is stripped on ElicitationResult (#1794) → must not be emitted.
    expect(r.hookSpecificOutput).toBeUndefined();
  });

  it('reads user_response.action (real CC field) for accept / decline / cancel', () => {
    for (const action of ['accept', 'decline', 'cancel'] as const) {
      const r = elicitationResultLogger(result({ user_response: { action } }));
      expect(r.continue).toBe(true);
    }
  });

  it('handles a missing user_response gracefully', () => {
    const r = elicitationResultLogger(result({ user_response: undefined }));
    expect(r.continue).toBe(true);
  });
});
